# Try to compile and run a simple test without gtest to verify correctness
g++ -std=c++17 -I/workspace/bustub/src/include \
    /workspace/bustub/src/primer/hyperloglog.cpp \
    /workspace/bustub/src/primer/hyperloglog_presto.cpp \
    -x c++ - << 'EOF' -o /tmp/hll_test 2>&1
#include <iostream>
#include <cstdint>
#include <string>
#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"

int main() {
    // Test 1: n_bits <= 0
    bustub::HyperLogLog<int64_t> hll1(-1);
    hll1.AddElem(1);
    std::cout << "Test1 (n_bits=-1): " << hll1.EstimateCardinality() << " (expected 0)" << std::endl;

    // Test 2: Basic HLL with 100 elements
    bustub::HyperLogLog<int64_t> hll2(4);
    for (int64_t i = 0; i < 100; i++) hll2.AddElem(i);
    std::cout << "Test2 (100 int64_t): " << hll2.EstimateCardinality() << " (expected ~100)" << std::endl;

    // Test 3: HLL with strings
    bustub::HyperLogLog<std::string> hll3(4);
    for (int i = 0; i < 100; i++) hll3.AddElem(std::to_string(i));
    std::cout << "Test3 (100 strings): " << hll3.EstimateCardinality() << " (expected ~100)" << std::endl;

    // Test 4: Presto n_bits=-1
    bustub::HyperLogLogPresto<int64_t> presto1(-1);
    presto1.AddElem(1);
    std::cout << "Test4 Presto (n_bits=-1): " << presto1.EstimateCardinality() << " (expected 0)" << std::endl;

    // Test 5: Presto with 100 elements
    bustub::HyperLogLogPresto<int64_t> presto2(4);
    for (int64_t i = 0; i < 100; i++) presto2.AddElem(i);
    std::cout << "Test5 Presto (100 int64_t): " << presto2.EstimateCardinality() << " (expected ~100)" << std::endl;

    // Test 6: Large cardinality
    bustub::HyperLogLog<int64_t> hll4(8);
    for (int64_t i = 0; i < 10000; i++) hll4.AddElem(i);
    std::cout << "Test6 (10000 int64_t, b=8): " << hll4.EstimateCardinality() << " (expected ~10000)" << std::endl;

    return 0;
}
