#include <iostream>
#include <iomanip>
#include <cstdint>
#include <cmath>
#include <string>
#include <bitset>
#include <map>
#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"
#include "common/util/hash_util.h"

int main() {
    // Check hash distribution for different n_bits
    for (int n_bits : {1, 2, 4, 8, 14}) {
        std::map<uint64_t, int> bucket_counts;
        size_t m = 1ULL << n_bits;

        for (int64_t i = 0; i < 1000; i++) {
            bustub::hash_t h = bustub::HashUtil::Hash(i);
            uint64_t idx = h >> (64 - n_bits);
            bucket_counts[idx]++;
        }

        int distinct_buckets = bucket_counts.size();
        std::cout << "n_bits=" << n_bits << " m=" << m 
                  << " distinct_buckets=" << distinct_buckets << "/" << m << std::endl;

        if (n_bits <= 4) {
            for (auto &[k,v] : bucket_counts) {
                std::cout << "  bucket[" << k << "] = " << v << std::endl;
            }
        }
    }

    // Try with string keys
    std::cout << "\nString key distribution (n_bits=4, m=16):" << std::endl;
    std::map<uint64_t, int> str_buckets;
    for (int i = 0; i < 100; i++) {
        bustub::hash_t h = bustub::HashUtil::Hash(std::to_string(i));
        uint64_t idx = h >> (64 - 4);
        str_buckets[idx]++;
    }
    for (auto &[k,v] : str_buckets) {
        std::cout << "  bucket[" << k << "] = " << v << std::endl;
    }

    return 0;
}
