#include <iostream>
#include <cstdint>
#include <string>
#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"

int main() {
    std::cout << "=== HyperLogLog Tests ===" << std::endl;

    // Test 1: n_bits <= 0
    {
        bustub::HyperLogLog<int64_t> hll(-1);
        hll.AddElem(1);
        auto est = hll.EstimateCardinality();
        std::cout << "Test n_bits=-1: est=" << est << " (expect 0)" << (est==0?" PASS":" FAIL") << std::endl;
    }

    // Test 2: n_bits = 0
    {
        bustub::HyperLogLog<int64_t> hll(0);
        hll.AddElem(1);
        auto est = hll.EstimateCardinality();
        std::cout << "Test n_bits=0: est=" << est << " (expect 0)" << (est==0?" PASS":" FAIL") << std::endl;
    }

    // Test 3: n_bits = 1
    {
        bustub::HyperLogLog<int64_t> hll(1);
        hll.AddElem(1);
        auto est = hll.EstimateCardinality();
        std::cout << "Test n_bits=1 single: est=" << est << std::endl;
    }

    // Test 4: Specific values for n_bits=4
    {
        bustub::HyperLogLog<int64_t> hll(4);
        for (int64_t i = 0; i < 10; i++) hll.AddElem(i);
        auto est = hll.EstimateCardinality();
        auto& db = hll.GetDenseBucket();
        std::cout << "Test n_bits=4, 10 elems: est=" << est << " regs=[";
        for (auto r : db) std::cout << (int)r << " ";
        std::cout << "]" << std::endl;
    }

    std::cout << "\n=== HyperLogLogPresto Tests ===" << std::endl;

    // Presto Test 1: n_bits <= 0
    {
        bustub::HyperLogLogPresto<int64_t> hll(-1);
        hll.AddElem(1);
        auto est = hll.EstimateCardinality();
        std::cout << "Presto n_bits=-1: est=" << est << " (expect 0)" << (est==0?" PASS":" FAIL") << std::endl;
    }

    // Presto Test 2: basic
    {
        bustub::HyperLogLogPresto<int64_t> hll(4);
        hll.AddElem(1LL);
        auto est = hll.EstimateCardinality();
        auto db = hll.GetDenseBucket();
        std::cout << "Presto n_bits=4 add(1): est=" << est << " dense=[";
        for (auto r : db) std::cout << std::hex << (int)r << " ";
        std::cout << std::dec << "]" << std::endl;

        // Check overflow bucket
        for (uint16_t i = 0; i < 16; i++) {
            auto ov = hll.GetOverflowBucketofIdx(i);
            if (ov > 0) {
                std::cout << "  overflow[" << i << "] = " << (int)ov << std::endl;
            }
        }
    }

    // Presto Test 3: check with known hash
    {
        bustub::HyperLogLogPresto<int64_t> hll(4);
        for (int64_t i = 0; i < 100; i++) hll.AddElem(i);
        auto est = hll.EstimateCardinality();
        std::cout << "Presto n_bits=4 100 elems: est=" << est << std::endl;
    }

    return 0;
}
