#pragma once

#include <algorithm>
#include <cstdint>
#include <string>

namespace bustub {

using hash_t = uint64_t;

class HashUtil {
 private:
  static const hash_t PRIME_FACTOR = 10000019;

 public:
  static inline hash_t HashBytes(const char *bytes, size_t length) {
    // https://github.com/greenplum-db/gpos/blob/b53c1acd6285de94044ff91fbee91589543feba4/libgpos/src/utils.cpp#L126
    hash_t hash = length;
    for (size_t i = 0; i < length; ++i) {
      hash = ((hash << 5) ^ (hash >> 27)) ^ static_cast<signed char>(bytes[i]);
    }
    return hash;
  }

  static inline hash_t CombineHashes(hash_t l, hash_t r) {
    hash_t both[2] = {};
    both[0] = l;
    both[1] = r;
    return HashBytes(reinterpret_cast<char *>(both), 2 * sizeof(hash_t));
  }

  static inline hash_t SumHashes(hash_t l, hash_t r) {
    return (l % PRIME_FACTOR + r % PRIME_FACTOR) % PRIME_FACTOR;
  }

  template <typename T>
  static inline hash_t Hash(const T &val) {
    return HashBytes(reinterpret_cast<const char *>(&val), sizeof(T));
  }

  template <>
  inline hash_t Hash(const std::string &val) {
    return HashBytes(val.c_str(), val.length());
  }
};

}  // namespace bustub

