namespace bustub {

template <typename KeyType>
class HyperLogLogPresto {
 public:
  explicit HyperLogLogPresto(int16_t n_leading_bits);

  auto AddElem(KeyType val) -> void;

  auto EstimateCardinality() const -> size_t;

  auto GetDenseBucket() const -> std::vector<uint8_t> { return dense_bucket_; }

  auto GetOverflowBucketofIdx(uint16_t idx) const -> uint8_t;

 private:
  auto ComputeBinary(const hash_t &hash) const -> std::bitset<64>;

  auto PositionOfLeftmostOne(const std::bitset<64> &bset) const -> uint64_t;

  int16_t n_leading_bits_;
  // dense_bucket_ stores 4 bits per bucket, packed 2 per byte
  // dense_bucket_[i/2] stores buckets i and i+1
  // lower 4 bits = bucket at even index, upper 4 bits = bucket at odd index
  std::vector<uint8_t> dense_bucket_;
  // overflow_buckets_ stores 4 bits per bucket, packed 2 per byte
  std::vector<uint8_t> overflow_buckets_;
  std::mutex mutex_;
};

