#include "primer/hyperloglog.h"

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : n_bits_(n_bits) {
  if (n_bits_ > 0) {
    size_t num_registers = 1ULL << n_bits_;
    registers_.resize(num_registers, 0);
  }
}

/** @brief Compute binary representation of a hash value. */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<64> {
  return std::bitset<64>(hash);
}

/**
 * @brief Function to compute position of leftmost one in the binary
 *        representation of a hash after the first n_bits_.
 *
 * @param bset - binary representation of hash
 * @return uint64_t - position of leftmost one (1-indexed from MSB of
 *                    remaining bits)
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<64> &bset) const -> uint64_t {
  // We check bits from position (63 - n_bits_) down to 0
  // (since bitset bit 63 is MSB, bit 0 is LSB)
  // The "remaining" bits are bits [63 - n_bits_] down to [0]
  int remaining = 64 - n_bits_;
  for (int i = remaining - 1; i >= 0; i--) {
    if (bset[i]) {
      // Position from left in the remaining bits
      return static_cast<uint64_t>(remaining - i);
    }
  }
  // All remaining bits are 0
  return static_cast<uint64_t>(remaining + 1);
}

/**
 * @brief Adds an element to the HyperLogLog data structure.
 * @param val - value to add
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  hash_t hash = HashUtil::Hash(val);
  std::bitset<64> bits = ComputeBinary(hash);

  // Extract top n_bits_ bits as register index
  // bits[63] is the MSB
  uint64_t idx = 0;
  for (int i = 0; i < n_bits_; i++) {
    idx = (idx << 1) | (bits[63 - i] ? 1 : 0);
  }

  // Compute position of leftmost one in remaining bits
  uint64_t pos = PositionOfLeftmostOne(bits);

  std::lock_guard<std::mutex> lock(mutex_);
  if (pos > registers_[idx]) {
    registers_[idx] = static_cast<uint8_t>(pos);
  }
}

/**
 * @brief Estimates the cardinality of the data seen so far.
 * @return size_t - estimated cardinality
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::EstimateCardinality() const -> size_t {
  if (n_bits_ <= 0) {
    return 0;
  }

  size_t m = registers_.size();
  double sum = 0.0;
  for (size_t i = 0; i < m; i++) {
    sum += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  double estimate = CONSTANT * static_cast<double>(m) * static_cast<double>(m) / sum;
  return static_cast<size_t>(std::floor(estimate));
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub

