#include <bitset>
#include <cstdint>
#include <string>

namespace bustub {

// Test 1: HyperLogLog with n_bits = -1 (or <= 0) should return 0
TEST(HyperLogLogTest, BasicTest1) {
  HyperLogLog<int64_t> hll(-1);
  hll.AddElem(1);
  hll.AddElem(2);
  ASSERT_EQ(hll.EstimateCardinality(), 0);
}

// Test 2: HyperLogLog int64_t small cardinality
TEST(HyperLogLogTest, BasicTest2) {
  HyperLogLog<int64_t> hll(4);
  for (int64_t i = 0; i < 100; i++) {
    hll.AddElem(i);
  }
  size_t est = hll.EstimateCardinality();
  // Should be within 30% of 100
  EXPECT_GT(est, 50U);
  EXPECT_LT(est, 200U);
}

// Test 3: HyperLogLog string
TEST(HyperLogLogTest, BasicTest3) {
  HyperLogLog<std::string> hll(4);
  for (int i = 0; i < 100; i++) {
    hll.AddElem(std::to_string(i));
  }
  size_t est = hll.EstimateCardinality();
  EXPECT_GT(est, 50U);
  EXPECT_LT(est, 200U);
}

// Test 4: HyperLogLog with n_bits = 0 should return 0
TEST(HyperLogLogTest, BasicTest4) {
  HyperLogLog<int64_t> hll(0);
  hll.AddElem(1);
  ASSERT_EQ(hll.EstimateCardinality(), 0);
}

// Test 5: HyperLogLog large cardinality
TEST(HyperLogLogTest, BasicTest5) {
  HyperLogLog<int64_t> hll(8);
  for (int64_t i = 0; i < 10000; i++) {
    hll.AddElem(i);
  }
  size_t est = hll.EstimateCardinality();
  EXPECT_GT(est, 7000U);
  EXPECT_LT(est, 13000U);
}

// Test 6: HyperLogLogPresto basic
TEST(HyperLogLogPrestoTest, BasicTest1) {
  HyperLogLogPresto<int64_t> hll(-1);
  hll.AddElem(1);
  ASSERT_EQ(hll.EstimateCardinality(), 0);
}

// Test 7: HyperLogLogPresto int64_t small cardinality
TEST(HyperLogLogPrestoTest, BasicTest2) {
  HyperLogLogPresto<int64_t> hll(4);
  for (int64_t i = 0; i < 100; i++) {
    hll.AddElem(i);
  }
  size_t est = hll.EstimateCardinality();
  EXPECT_GT(est, 50U);
  EXPECT_LT(est, 200U);
}

// Test 8: HyperLogLogPresto string
TEST(HyperLogLogPrestoTest, BasicTest3) {
  HyperLogLogPresto<std::string> hll(4);
  for (int i = 0; i < 100; i++) {
    hll.AddElem(std::to_string(i));
  }
  size_t est = hll.EstimateCardinality();
  EXPECT_GT(est, 50U);
  EXPECT_LT(est, 200U);
}

// Test 9: HyperLogLogPresto large cardinality
TEST(HyperLogLogPrestoTest, BasicTest4) {
  HyperLogLogPresto<int64_t> hll(8);
  for (int64_t i = 0; i < 10000; i++) {
    hll.AddElem(i);
  }
  size_t est = hll.EstimateCardinality();
  EXPECT_GT(est, 7000U);
  EXPECT_LT(est, 13000U);
