#include "primer/hyperloglog_presto.h"

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : n_leading_bits_(n_leading_bits) {
  if (n_leading_bits_ > 0) {
    size_t num_buckets = 1ULL << n_leading_bits_;
    // Each byte stores 2 bucket values (4 bits each), so size = num_buckets / 2
    // For odd num_buckets, we round up
    dense_bucket_.resize((num_buckets + 1) / 2, 0);
    overflow_buckets_.resize((num_buckets + 1) / 2, 0);
  }
}

/** @brief Compute binary representation of a hash value. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<64> {
  return std::bitset<64>(hash);
}

/**
 * @brief Function to compute position of leftmost one in the binary
 *        representation of a hash after the first n_leading_bits_.
 */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::PositionOfLeftmostOne(const std::bitset<64> &bset) const -> uint64_t {
  int remaining = 64 - n_leading_bits_;
  for (int i = remaining - 1; i >= 0; i--) {
    if (bset[i]) {
      return static_cast<uint64_t>(remaining - i);
    }
  }
  return static_cast<uint64_t>(remaining + 1);
}

/**
 * @brief Get the overflow bucket value for a given index.
 *
 * @param idx - bucket index
 * @return uint8_t - overflow value (4-bit)
 */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::GetOverflowBucketofIdx(uint16_t idx) const -> uint8_t {
  if (n_leading_bits_ <= 0) {
    return 0;
  }
  size_t byte_idx = idx / 2;
  if (byte_idx >= overflow_buckets_.size()) {
    return 0;
  }
  if (idx % 2 == 0) {
    return overflow_buckets_[byte_idx] & 0x0F;
  }
  return (overflow_buckets_[byte_idx] >> 4) & 0x0F;
}

/**
 * @brief Adds an element to the HyperLogLogPresto data structure.
 * @param val - value to add
 */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ <= 0) {
    return;
  }

  hash_t hash = HashUtil::Hash(val);
  std::bitset<64> bits = ComputeBinary(hash);

  // Extract top n_leading_bits_ bits as bucket index
  uint64_t idx = 0;
  for (int i = 0; i < n_leading_bits_; i++) {
    idx = (idx << 1) | (bits[63 - i] ? 1 : 0);
  }

  // Compute position of leftmost one in remaining bits
  uint64_t pos = PositionOfLeftmostOne(bits);

  std::lock_guard<std::mutex> lock(mutex_);

  // Get current bucket value
  size_t byte_idx = idx / 2;
  uint8_t current_dense;
  uint8_t current_overflow;

  if (idx % 2 == 0) {
    current_dense = dense_bucket_[byte_idx] & 0x0F;
    current_overflow = overflow_buckets_[byte_idx] & 0x0F;
  } else {
    current_dense = (dense_bucket_[byte_idx] >> 4) & 0x0F;
    current_overflow = (overflow_buckets_[byte_idx] >> 4) & 0x0F;
  }

  // Combined current value: overflow * 16 + dense? No, let's think...
  // The value is split: lower 4 bits in dense, upper 4 bits in overflow
  // total value = (overflow << 4) | dense
  // But that would be 8-bit total, supporting values 0-255
  // Actually, let's use: value = overflow_val * 16 + dense_val
  // where overflow_val and dense_val are each 4-bit (0-15)
  // This gives max value of 15*16 + 15 = 255

  // For HLL with b=4, max position = 64-4+1 = 61, which fits in 6 bits
  // So 4+4=8 bits is more than enough

  uint64_t current_val = (static_cast<uint64_t>(current_overflow) << 4) | current_dense;

  if (pos > current_val) {
    uint8_t new_dense = static_cast<uint8_t>(pos & 0x0F);
    uint8_t new_overflow = static_cast<uint8_t>((pos >> 4) & 0x0F);

    if (idx % 2 == 0) {
      dense_bucket_[byte_idx] = (dense_bucket_[byte_idx] & 0xF0) | new_dense;
      overflow_buckets_[byte_idx] = (overflow_buckets_[byte_idx] & 0xF0) | new_overflow;
    } else {
      dense_bucket_[byte_idx] = (dense_bucket_[byte_idx] & 0x0F) | (new_dense << 4);
      overflow_buckets_[byte_idx] = (overflow_buckets_[byte_idx] & 0x0F) | (new_overflow << 4);
    }
  }
}

/**
 * @brief Estimates the cardinality of the data seen so far.
