#include <bitset>
#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"
#include "common/util/hash_util.h"

int main() {
    int n_bits = 4;
    int m = 1 << n_bits;

    // Show first few hashes and what we compute
    for (int64_t i = 0; i < 5; i++) {
        bustub::hash_t h = bustub::HashUtil::Hash(i);
        std::bitset<64> bits(h);

        // Extract top n_bits as index
        uint64_t idx = 0;
        for (int b = 0; b < n_bits; b++) {
            idx = (idx << 1) | (bits[63-b] ? 1 : 0);
        }

        // Find leftmost 1 in remaining 60 bits
        int remaining = 64 - n_bits;
        uint64_t pos = remaining + 1; // default
        for (int b = remaining-1; b >= 0; b--) {
            if (bits[b]) {
                pos = remaining - b;
                break;
            }
        }

        std::cout << "val=" << i << " hash=" << std::hex << h << std::dec 
                  << " idx=" << idx << " pos=" << pos << std::endl;
    }

    // Test with 100 elements - show register values
    bustub::HyperLogLog<int64_t> hll(4);
    for (int64_t i = 0; i < 100; i++) hll.AddElem(i);

    auto regs = hll.GetDenseBucket();
    std::cout << "\nRegisters: ";
    for (auto r : regs) std::cout << (int)r << " ";
    std::cout << std::endl;

    double sum = 0;
    for (auto r : regs) sum += std::pow(2.0, -(double)r);
    std::cout << "Sum of 2^(-r): " << sum << std::endl;
    std::cout << "Estimate: " << 0.79402 * m * m / sum << std::endl;

    return 0;
}
